CHIPS // jetons (montant dans `value`)\n  VIP // abonnement VIP (durée dans `value`, remis en RP par le staff)\n  CUSTOM // objet RP / lot physique (description dans `label`)\n}\n\nenum RaffleTicketStatus {\n  ACTIVE // en lice pour les prochains tirages\n  WON // a gagné -> retiré du pool\n}\n\nenum RaffleClaimStatus {\n  UNCLAIMED // ticket gagnant, en attente que le joueur ouvre sa réclamation\n  CLAIMED // lot réclamé/remis par le staff\n  EXPIRED // délai de réclamation dépassé -> lot perdu\n}\n\n/// Une campagne de tombola (ex : \"Tombola de lancement\", 2 semaines).\n/// En principe une seule en statut OPEN à la fois.\nmodel RaffleCampaign {\n  id                String               @id @default(cuid())\n  name              String\n  description       String?\n  status            RaffleCampaignStatus @default(DRAFT)\n  ticketPrice       BigInt // prix d'un ticket en jetons\n  maxTicketsPerUser Int // plafond global sur toute la campagne\n  startsAt          DateTime // ouverture des achats\n  endsAt            DateTime // fin de campagne (après le dernier tirage)\n  createdBy         String // userId admin créateur\n  createdAt         DateTime             @default(now())\n  updatedAt         DateTime             @updatedAt\n\n  draws   RaffleDraw[]\n  tickets RaffleTicket[]\n\n  @@index([status])\n  @@index([startsAt, endsAt])\n}\n\n/// Un tirage programmé au sein d'une campagne (un tous les 2 jours, ~7 au total).\nmodel RaffleDraw {\n  id          String           @id @default(cuid())\n  campaignId  String\n  label       String? // ex : \"Tirage #3\"\n  scheduledAt DateTime // date/heure prévue du tirage\n  status      RaffleDrawStatus @default(PENDING)\n  executedAt  DateTime? // rempli quand le tirage est exécuté\n  seed        String? // graine RNG conservée pour l'audit\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n\n  campaign   RaffleCampaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n  prizes     RafflePrize[]\n  wonTickets RaffleTicket[] @relation(\"RaffleTicketWonDraw\")\n\n  @@index([campaignId])\n  @@index([status, scheduledAt])\n}\n\n/// Un lot rattaché à un tirage précis (lots fixes définis à l'avance).\n/// `quantity` = nombre de gagnants pour ce lot lors du tirage.\nmodel RafflePrize {\n  id        String          @id @default(cuid())\n  drawId    String\n  type      RafflePrizeType\n  label     String // \"1 000 000 jetons\", \"VIP 1 mois\", \"Plaque collector\"\n  value     String? // montant (jetons) ou durée VIP ('1_MONTH'...) ; null pour CUSTOM\n  rank      Int             @default(1) // ordre d'affichage / prestige (1 = lot principal)\n  quantity  Int             @default(1) // nombre de gagnants pour ce lot\n  createdAt DateTime        @default(now())\n\n  draw       RaffleDraw     @relation(fields: [drawId], references: [id], onDelete: Cascade)\n  wonTickets RaffleTicket[] @relation(\"RaffleTicketWonPrize\")\n\n  @@index([drawId])\n}\n\n/// Un ticket acheté par un joueur. Cumulatif et permanent jusqu'à victoire.\nmodel RaffleTicket {\n  id           String             @id @default(cuid())\n  campaignId   String\n  userId       String\n  ticketNumber Int // numéro séquentiel dans la campagne\n  status       RaffleTicketStatus @default(ACTIVE)\n  purchasedAt  DateTime           @default(now())\n\n  // Renseignés uniquement si le ticket a gagné\n  wonDrawId     String?\n  wonPrizeId    String?\n  claimStatus   RaffleClaimStatus? // null tant que ACTIVE ; UNCLAIMED dès qu'il gagne\n  claimDeadline DateTime? // délai pour ouvrir la réclamation (tirage + 3 jours)\n  claimedAt     DateTime?\n\n  campaign RaffleCampaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n  user     User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  wonDraw  RaffleDraw?    @relation(\"RaffleTicketWonDraw\", fields: [wonDrawId], references: [id], onDelete: SetNull)\n  wonPrize RafflePrize?   @relation(\"RaffleTicketWonPrize\", fields: [wonPrizeId], references: [id], onDelete: SetNull)\n\n  @@unique([campaignId, ticketNumber])\n  @@index([campaignId, status])\n  @@index([userId, campaignId])\n  @@index([wonDrawId])\n  @@index([claimStatus, claimDeadline])\n}\n",
